eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   CAPABILITIES: () => (/* binding */ CAPABILITIES),\n/* harmony export */   allWork: () => (/* binding */ allWork),\n/* harmony export */   featuredWork: () => (/* binding */ featuredWork)\n/* harmony export */ });\n/**\n * Case study data.\n * CMS-ready structure — replace with actual fetch from Contentful / Sanity / etc.\n *\n * capability maps to one of four service pillars:\n *   'Growth Systems' | 'Digital Platforms' | 'Performance' | 'Brand Presence'\n */ const featuredWork = [\n    {\n        id: 'cs-01',\n        slug: 'b2b-saas-pipeline',\n        client: 'Meridian SaaS',\n        industry: 'B2B Software',\n        headline: 'Rebuilt demand engine — 347% more qualified pipeline in 90 days',\n        description: 'Rebuilt outbound sequencing, ICP targeting, and LinkedIn presence from scratch. Replaced spray-and-pray with signal-based prospecting, cutting CAC by half while tripling demo bookings.',\n        challenge: 'Outbound was generating volume but almost no qualified pipeline — CAC was unsustainable and the sales team was fielding the wrong conversations.',\n        solution: 'Rebuilt ICP definition, signal-based sequencing, and LinkedIn organic from the ground up — replacing volume targeting with intent-driven outreach.',\n        challengeDetail: \"The outbound team was burning through 400+ contacts per week with open rates below 8% and a demo-to-close ratio that had stalled for two quarters. The ICP was too broad, sequencing was generic, and LinkedIn was posting content with no connection to buyer intent. Leadership knew volume wasn't the answer — but had no system to replace it with.\",\n        solutionDetail: 'We rebuilt ICP from firmographic signals to behavioral triggers: job change events, funding rounds, and tech stack additions. New sequencing mapped directly to those triggers — short, specific, with relevance built into the first line. LinkedIn shifted from broadcast content to demand-creation: POV posts surfacing problems buyers were actively facing, seeding inbound conversations in parallel with outbound.',\n        impact: 'Within 90 days, demo bookings tripled and CAC dropped by half — not because volume increased, but because the right conversations were starting. The sales team closed deals faster because prospects arrived already aligned with the problem framing. The pipeline transformation held and compounded through the following quarter.',\n        pillarsInvolved: [\n            'Growth Systems'\n        ],\n        quote: {\n            text: \"We went from chasing volume to having qualified buyers book demos we didn't have to fight for. The system just works.\",\n            author: 'Alex Chen',\n            role: 'Head of Revenue, Meridian SaaS'\n        },\n        capability: 'Growth Systems',\n        gradientFrom: '#6C3AFF',\n        gradientTo: '#3B82F6',\n        metrics: [\n            {\n                value: 347,\n                suffix: '%',\n                label: 'Qualified Pipeline',\n                decimals: 0\n            },\n            {\n                value: 52,\n                suffix: '%',\n                label: 'CAC Reduction',\n                decimals: 0\n            },\n            {\n                value: 3.2,\n                suffix: 'x',\n                label: 'Demo Bookings',\n                decimals: 1\n            }\n        ],\n        tags: [\n            'Demand Gen',\n            'LinkedIn',\n            'Outbound'\n        ],\n        year: 2025\n    },\n    {\n        id: 'cs-02',\n        slug: 'ecom-brand-authority',\n        client: 'Forge Supply Co.',\n        industry: 'DTC E-commerce',\n        headline: 'Brand overhaul drove 2.8x revenue in one product cycle',\n        description: 'Repositioned a commoditised product brand with a narrative-first content system and paid social engine. New creative direction and full-funnel strategy compounded into a breakout quarter.',\n        challenge: 'A strong product was losing ground to cheaper competitors — the brand had no differentiated positioning and paid channels were burning budget on bottom-of-funnel only.',\n        solution: 'Built a narrative-led brand architecture and full-funnel paid social system with creative direction, audience segmentation, and a retention email layer.',\n        challengeDetail: \"The product was genuinely good — but the brand was invisible at the top of funnel and over-indexed on discount-driven retargeting at the bottom. Paid social was averaging a 1.4x ROAS on prospecting audiences. Repeat purchase rates were low because customers had no emotional connection to the brand — they had just found a deal.\",\n        solutionDetail: \"We rebuilt brand architecture around a clear identity: rugged utility, maker culture, and the pride of lasting tools. New creative direction established a visual language and narrative voice, then fed into a full-funnel paid social system — awareness creative to build affinity, mid-funnel story sequences to educate, and conversion content that didn't rely on discounts. An email retention layer locked in repeat buyers.\",\n        impact: 'The brand effect compounded into the numbers: ROAS on prospecting moved from 1.4x to 4.1x as creative quality lifted click-through, and repeat purchase rate grew to 68% as customers developed brand loyalty rather than deal loyalty. Revenue grew 2.8x over one product cycle — a result that held into the following season.',\n        pillarsInvolved: [\n            'Performance',\n            'Brand Presence'\n        ],\n        capability: 'Performance',\n        gradientFrom: '#EC4899',\n        gradientVia: '#8B5CF6',\n        gradientTo: '#3B82F6',\n        metrics: [\n            {\n                value: 2.8,\n                suffix: 'x',\n                label: 'Revenue Growth',\n                decimals: 1\n            },\n            {\n                value: 4.1,\n                suffix: 'x',\n                label: 'ROAS',\n                decimals: 1\n            },\n            {\n                value: 68,\n                suffix: '%',\n                label: 'Repeat Purchase Rate',\n                decimals: 0\n            }\n        ],\n        tags: [\n            'Brand Strategy',\n            'Paid Social',\n            'Content'\n        ],\n        year: 2025\n    },\n    {\n        id: 'cs-03',\n        slug: 'professional-services-seo',\n        client: 'Arctus Legal',\n        industry: 'Professional Services',\n        headline: 'Organic became #1 revenue channel — 220% more inbound leads in 6 months',\n        description: 'Built a full content moat from a blank slate: keyword architecture, pillar pages, and editorial calendar mapped to buyer intent. SEO surpassed paid in revenue contribution within two quarters.',\n        challenge: 'The firm had no digital presence — all new business came from referrals, creating unpredictable revenue and zero scalable acquisition.',\n        solution: 'Built a content architecture from zero: ICP-mapped keyword strategy, pillar pages targeting high-intent searches, and a systematic editorial cadence.',\n        challengeDetail: 'Referral-led growth had served the firm well for years, but it created revenue that was invisible in advance and impossible to scale. There was no digital presence — the website was a business card, not a discovery channel. One partner retirement had already cost the firm three key client relationships, exposing the fragility of relationship-only acquisition.',\n        solutionDetail: \"We built the content infrastructure from zero: an ICP-mapped keyword architecture across 14 practice areas, pillar pages targeting commercial and transactional search intent, and an editorial calendar tied to the firm's advisory calendar. Every piece of content was written to rank for specific searches that qualified buyers were actively making — not thought leadership for its own sake.\",\n        impact: \"Organic became the firm's first predictable acquisition channel. Within six months, inbound leads from search grew 220% and SEO overtook paid as the top revenue-contributing channel. The content asset base continued compounding with minimal maintenance, generating increasing returns month over month.\",\n        pillarsInvolved: [\n            'Brand Presence',\n            'Performance'\n        ],\n        capability: 'Brand Presence',\n        gradientFrom: '#10B981',\n        gradientTo: '#0EA5E9',\n        metrics: [\n            {\n                value: 220,\n                suffix: '%',\n                label: 'Inbound Leads',\n                decimals: 0\n            },\n            {\n                value: 1,\n                prefix: '#',\n                label: 'Organic Channel Rank',\n                decimals: 0\n            },\n            {\n                value: 8.4,\n                suffix: 'x',\n                label: 'Content ROI',\n                decimals: 1\n            }\n        ],\n        tags: [\n            'SEO',\n            'Content Strategy',\n            'Lead Gen'\n        ],\n        year: 2024\n    },\n    {\n        id: 'cs-04',\n        slug: 'saas-platform-rebuild',\n        client: 'Helio Digital',\n        industry: 'Digital Media',\n        headline: 'Platform rebuild cut churn by 41% and reduced time-to-value by 60%',\n        description: 'Rebuilt the core product onboarding flow and dashboard architecture following a spike in churn. New UX reduced activation friction, surfaced value faster, and restored NPS to healthy territory.',\n        challenge: 'A technically sound product was losing customers in the first 30 days — onboarding was fragmented and users couldn\\'t reach the \"aha moment\" before churning.',\n        solution: 'Redesigned the onboarding journey end-to-end: new activation sequence, progressive disclosure UI, in-product guidance, and a first-session success metric framework.',\n        challengeDetail: \"Churn was clustering in days 1–30. Product analytics showed users were reaching the core feature — but not consistently extracting value before their trial lapsed. The onboarding flow had been built feature-first rather than outcome-first: it showed users everything the product could do, but didn't guide them to the one thing that would make them stay.\",\n        solutionDetail: 'We redesigned onboarding end-to-end around a single first-session success metric: completing one meaningful workflow. Progressive disclosure replaced the feature tour — users were shown only what they needed to succeed in their first session. In-product guidance cues triggered contextually rather than linearly, and a post-activation email sequence reinforced early wins before the second login.',\n        impact: 'Churn in the first 30 days dropped 41%. Time-to-value — the interval between signup and first meaningful outcome — fell 60%. NPS improved 34 points as users who reached activation consistently reported higher satisfaction. The changes required no new engineering investment — only a structural rethink of how existing product capabilities were sequenced.',\n        pillarsInvolved: [\n            'Digital Platforms',\n            'Growth Systems'\n        ],\n        capability: 'Digital Platforms',\n        gradientFrom: '#F59E0B',\n        gradientTo: '#EF4444',\n        metrics: [\n            {\n                value: 41,\n                suffix: '%',\n                label: 'Churn Reduction',\n                decimals: 0\n            },\n            {\n                value: 60,\n                suffix: '%',\n                label: 'Faster Time-to-Value',\n                decimals: 0\n            },\n            {\n                value: 34,\n                suffix: 'pt',\n                label: 'NPS Improvement',\n                decimals: 0\n            }\n        ],\n        tags: [\n            'Product UX',\n            'Onboarding',\n            'Retention'\n        ],\n        year: 2024\n    },\n    {\n        id: 'cs-05',\n        slug: 'real-estate-crm-automation',\n        client: 'Claros Group',\n        industry: 'Real Estate',\n        headline: 'CRM and automation stack cut deal time by 38% and doubled follow-up coverage',\n        description: 'Designed and deployed a revenue operations stack for a mid-market real estate firm: CRM configuration, automated follow-up sequences, and pipeline reporting that gave leadership full visibility.',\n        challenge: 'The team was operating from spreadsheets and email — deals were slipping through manual gaps and leadership had no pipeline visibility.',\n        solution: 'Built a full RevOps infrastructure: CRM implementation, automated nurture sequences, deal-stage scoring, and a live pipeline dashboard wired to their existing tools.',\n        challengeDetail: 'The team was managing a 40-deal pipeline from spreadsheets, shared inboxes, and memory. Follow-up was manual and inconsistent — senior brokers were re-entering data across multiple tools and deals were regularly slipping because no one owned the next step. Leadership had no real-time pipeline view, making forecasting and resourcing permanently reactive.',\n        solutionDetail: \"We designed and deployed a full RevOps infrastructure: CRM implementation with custom deal stages and ownership rules, automated follow-up sequences triggered by deal movement, and a live pipeline dashboard pulling from real-time data. Process documentation and team training ensured adoption. Integrations connected their existing calendar, email, and document tools — structure built around what was already there, not a rip-and-replace.\",\n        impact: 'Deal cycle time dropped 38% as automated touchpoints eliminated the gap between stages. Follow-up coverage doubled because sequences ran without manual triggers. Leadership gained full pipeline visibility for the first time — enabling forecasting and resourcing decisions that had never been possible before.',\n        pillarsInvolved: [\n            'Growth Systems'\n        ],\n        quote: {\n            text: 'We finally know exactly where every deal is without chasing our team for updates. The pipeline runs itself now.',\n            author: 'Marcus Webb',\n            role: 'Managing Director, Claros Group'\n        },\n        capability: 'Growth Systems',\n        gradientFrom: '#6C3AFF',\n        gradientVia: '#8B5CF6',\n        gradientTo: '#EC4899',\n        metrics: [\n            {\n                value: 38,\n                suffix: '%',\n                label: 'Faster Deal Cycle',\n                decimals: 0\n            },\n            {\n                value: 2,\n                suffix: 'x',\n                label: 'Follow-up Coverage',\n                decimals: 0\n            },\n            {\n                value: 100,\n                suffix: '%',\n                label: 'Pipeline Visibility',\n                decimals: 0\n            }\n        ],\n        tags: [\n            'RevOps',\n            'CRM',\n            'Automation'\n        ],\n        year: 2024\n    },\n    {\n        id: 'cs-06',\n        slug: 'pe-brand-positioning',\n        client: 'Vela Partners',\n        industry: 'Private Equity',\n        headline: 'Repositioned fund brand — 3x inbound LP enquiries within one quarter',\n        description: \"Rebuilt the firm's digital presence and positioning narrative for LP outreach: new website, investment thesis articulation, and a targeted content programme aligned with fundraising cycle.\",\n        challenge: \"An established fund with a strong track record was invisible digitally — LPs couldn't find them organically and the existing materials didn't reflect the calibre of the portfolio.\",\n        solution: 'Rebuilt brand positioning from the investment thesis down: new narrative architecture, website rebuild, and a thought-leadership content system timed to the fundraising cycle.',\n        challengeDetail: \"An established fund with a 12-year track record and a portfolio of genuine outliers was digitally invisible. LP introductions came entirely from existing relationships. When LPs searched for Vela, they found a dated website with no investment thesis, no portfolio narrative, and nothing that reflected what made the firm distinct. In a market where credibility is built before the first call, the digital gap had become a commercial liability.\",\n        solutionDetail: 'We rebuilt the brand from the investment thesis down: a clear positioning narrative around sector focus and operational support — not just capital. A new website communicated the thesis, portfolio philosophy, and team credibility in a format built for LP due diligence. A targeted thought-leadership programme — timed to the fundraising cycle — built organic visibility among the exact LP profiles the fund was actively targeting.',\n        impact: 'LP inbound enquiries tripled in the first quarter following the rebrand. Organic traffic grew 58% as the thought-leadership content began ranking for sector-specific searches. Twelve qualified LP introductions came through digital channels — a channel that had contributed zero in the prior three years.',\n        pillarsInvolved: [\n            'Brand Presence',\n            'Digital Platforms'\n        ],\n        capability: 'Brand Presence',\n        gradientFrom: '#0EA5E9',\n        gradientTo: '#6C3AFF',\n        metrics: [\n            {\n                value: 3,\n                suffix: 'x',\n                label: 'LP Inbound Enquiries',\n                decimals: 0\n            },\n            {\n                value: 58,\n                suffix: '%',\n                label: 'Organic Traffic Growth',\n                decimals: 0\n            },\n            {\n                value: 12,\n                label: 'Qualified LP Introductions',\n                decimals: 0\n            }\n        ],\n        tags: [\n            'Brand Strategy',\n            'Web',\n            'Thought Leadership'\n        ],\n        year: 2024\n    }\n];\n/** All case studies — use for full index pages. */ const allWork = featuredWork;\nconst CAPABILITIES = [\n    'All',\n    'Growth Systems',\n    'Digital Platforms',\n    'Performance',\n    'Brand Presence'\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/data/work.ts\n");

